        DIBUJAR_CORAZON_M1 <= '0'; DIBUJAR_CORAZON_M2 <= '0'; DIBUJAR_CORAZON_M3 <= '0'; DIBUJAR_CORAZON_M4 <= '0'; DIBUJAR_CORAZON_M5 <= '0';
        DIBUJAR_CORAZON_M6 <= '0'; DIBUJAR_CORAZON_M7 <= '0'; DIBUJAR_CORAZON_M8 <= '0'; DIBUJAR_CORAZON_M9 <= '0'; DIBUJAR_CORAZON_M10 <= '0';
		  DIBUJAR_FLIP <= '0'; DIBUJAR_FLOP <= '0';

			--Kirby
        if (pixel_x >= KIRBY_X and pixel_x < KIRBY_X + 32 and pixel_y >= KIRBY_Y and pixel_y < KIRBY_Y + 32) then
            DIBUJAR_KIRBY <= '1';
		  end if;
			--Villano
        if(pixel_x >= VILLANO_X and pixel_x < VILLANO_X + 64 and pixel_y >= VILLANO_Y and pixel_y < VILLANO_Y + 64) then
            DIBUJAR_VILLANO <= '1';
		  end if;
				
				
        -- Estrellas Kirby 
        if(pixel_x >= ESTRELLAK1_X and pixel_x < ESTRELLAK1_X + 16 and pixel_y >= ESTRELLAK1_Y and pixel_y < ESTRELLAK1_Y + 16) then
            DIBUJAR_ESTRELLA_K1 <= '1';
		  end if;
		  
        if(pixel_x >= ESTRELLAK2_X and pixel_x < ESTRELLAK2_X + 16 and pixel_y >= ESTRELLAK2_Y and pixel_y < ESTRELLAK2_Y + 16) then
            DIBUJAR_ESTRELLA_K2 <= '1'; 
		  end if; 
		  
        if(pixel_x >= ESTRELLAK3_X and pixel_x < ESTRELLAK3_X + 16 and pixel_y >= ESTRELLAK3_Y and pixel_y < ESTRELLAK3_Y + 16) then
            DIBUJAR_ESTRELLA_K3 <= '1'; 
		  end if;
				
				
        -- Estrellas Villano
        if(pixel_x >= ESTRELLAV1_X and pixel_x < ESTRELLAV1_X + 32 and pixel_y >= ESTRELLAV1_Y and pixel_y < ESTRELLAV1_Y + 32) then
            DIBUJAR_ESTRELLA_V1 <= '1';
		  end if;
		  
        if(pixel_x >= ESTRELLAV2_X and pixel_x < ESTRELLAV2_X + 32 and pixel_y >= ESTRELLAV2_Y and pixel_y < ESTRELLAV2_Y + 32) then
            DIBUJAR_ESTRELLA_V2 <= '1';  
		  end if;
		
        if(pixel_x >= ESTRELLAV3_X and pixel_x < ESTRELLAV3_X + 32 and pixel_y >= ESTRELLAV3_Y and pixel_y < ESTRELLAV3_Y + 32) then
            DIBUJAR_ESTRELLA_V3 <= '1';
		  end if;	
				
        if(pixel_x >= ESTRELLAV4_X and pixel_x < ESTRELLAV4_X + 32 and pixel_y >= ESTRELLAV4_Y and pixel_y < ESTRELLAV4_Y + 32) then
            DIBUJAR_ESTRELLA_V4 <= '1';
        end if;
		
		
			--Corazones
        if (pixel_x >= POS_CORA1_X and pixel_x < POS_CORA1_X + 32 and pixel_y >= POS_CORAS_Y and pixel_y < POS_CORAS_Y + 32 and VIDA_K >= 1) then
            DIBUJAR_CORAZON1 <= '1';
		  end if;
		  
        if (pixel_x >= POS_CORA2_X and pixel_x < POS_CORA2_X + 32 and pixel_y >= POS_CORAS_Y and pixel_y < POS_CORAS_Y + 32 and VIDA_K >= 2) then
            DIBUJAR_CORAZON2 <= '1';
		  end if;
		  
        if(pixel_x >= POS_CORA3_X and pixel_x < POS_CORA3_X + 32 and pixel_y >= POS_CORAS_Y and pixel_y < POS_CORAS_Y + 32 and VIDA_K = 3) then
            DIBUJAR_CORAZON3 <= '1';
        end if;


        if (pixel_x >= POS_CORAM1_X and pixel_x < POS_CORAM1_X + 32 and pixel_y >= POS_CORAS_Y and pixel_y < POS_CORAS_Y + 32 and VIDA_V >= 1) then
            DIBUJAR_CORAZON_M1 <= '1';
		  end if;
		  
        if (pixel_x >= POS_CORAM2_X and pixel_x < POS_CORAM2_X + 32 and pixel_y >= POS_CORAS_Y and pixel_y < POS_CORAS_Y + 32 and VIDA_V >= 2) then
            DIBUJAR_CORAZON_M2 <= '1';
		  end if;
		  
        if(pixel_x >= POS_CORAM3_X and pixel_x < POS_CORAM3_X + 32 and pixel_y >= POS_CORAS_Y and pixel_y < POS_CORAS_Y + 32 and VIDA_V >= 3) then
            DIBUJAR_CORAZON_M3 <= '1';
		  end if;
		  
        if(pixel_x >= POS_CORAM4_X and pixel_x < POS_CORAM4_X + 32 and pixel_y >= POS_CORAS_Y and pixel_y < POS_CORAS_Y + 32 and VIDA_V >= 4) then
            DIBUJAR_CORAZON_M4 <= '1';
		  end if;	
		  
		  if(pixel_x >= POS_CORAM5_X and pixel_x < POS_CORAM5_X + 32 and pixel_y >= POS_CORAS_Y and pixel_y < POS_CORAS_Y + 32 and VIDA_V >= 5) then
            DIBUJAR_CORAZON_M5 <= '1';
		  end if;
		  
        if(pixel_x >= POS_CORAM6_X and pixel_x < POS_CORAM6_X + 32 and pixel_y >= POS_CORAS_Y and pixel_y < POS_CORAS_Y + 32 and VIDA_V >= 6) then
            DIBUJAR_CORAZON_M6 <= '1';
		  end if;
		  
        if(pixel_x >= POS_CORAM7_X and pixel_x < POS_CORAM7_X + 32 and pixel_y >= POS_CORAS_Y and pixel_y < POS_CORAS_Y + 32 and VIDA_V >= 7) then
            DIBUJAR_CORAZON_M7 <= '1';
		  end if;	
				
        if(pixel_x >= POS_CORAM8_X and pixel_x < POS_CORAM8_X + 32 and pixel_y >= POS_CORAS_Y and pixel_y < POS_CORAS_Y + 32 and VIDA_V >= 8) then
            DIBUJAR_CORAZON_M8 <= '1';
		  end if;
		  
        if(pixel_x >= POS_CORAM9_X and pixel_x < POS_CORAM9_X + 32 and pixel_y >= POS_CORAS_Y and pixel_y < POS_CORAS_Y + 32 and VIDA_V >= 9) then
            DIBUJAR_CORAZON_M9 <= '1';
		  end if;
		  
        if(pixel_x >= POS_CORAM10_X and pixel_x < POS_CORAM10_X + 32 and pixel_y >= POS_CORAS_Y and pixel_y < POS_CORAS_Y + 32 and VIDA_V = 10) then
            DIBUJAR_CORAZON_M10 <= '1';
        end if;
		  
		  --Pantalla de Ganar Ganar Pollo para Cenar
		  if(pixel_x >= POS_FLIPX and pixel_x < POS_FLIPX + 240 and pixel_y >= POS_FLIPY and pixel_y < POS_FLIPY + 100 and ESTADOJUEGO = "11") then
            DIBUJAR_FLIP <= '1';
        end if;
		  
		  --Pantalla de Floppear
		  if(pixel_x >= POS_FLOPX and pixel_x < POS_FLOPX + 260 and pixel_y >= POS_FLOPY and pixel_y < POS_FLOPY + 100 and ESTADOJUEGO = "10") then
            DIBUJAR_FLOP <= '1';
        end if;
		  
    end process;


    DIBUJANTE : process(DIBUJAR, pixel_x, pixel_y, DIBUJAR_KIRBY, DIBUJAR_VILLANO, 
                        DIBUJAR_ESTRELLA_K1, DIBUJAR_ESTRELLA_K2, DIBUJAR_ESTRELLA_K3,
                        DIBUJAR_ESTRELLA_V1, DIBUJAR_ESTRELLA_V2, DIBUJAR_ESTRELLA_V3, DIBUJAR_ESTRELLA_V4,
                        DIBUJAR_CORAZON1, DIBUJAR_CORAZON2, DIBUJAR_CORAZON3, 
                        DIBUJAR_CORAZON_M1, DIBUJAR_CORAZON_M2, DIBUJAR_CORAZON_M3, DIBUJAR_CORAZON_M4, DIBUJAR_CORAZON_M5,
                        DIBUJAR_CORAZON_M6, DIBUJAR_CORAZON_M7, DIBUJAR_CORAZON_M8, DIBUJAR_CORAZON_M9, DIBUJAR_CORAZON_M10)
        
          variable color_v : std_logic_vector(11 downto 0);
          
          -- Variables para escalar los corazones y estrellas(2x)
          variable corazon_map_x : integer range 0 to 15;
          variable corazon_map_y : integer range 0 to 15;
          variable estrella_map_x : integer range 0 to 15;
			 variable estrella_map_y : integer range 0 to 15;
    begin
     
        if (DIBUJAR = '0') then 
            color_v := X"000";
        else 
            --Fondo base
            color_v := FONDO(pixel_y - offset_y, pixel_x - offset_x);

            --Estrellas Kirby (Prioridad baja)
            if (DIBUJAR_ESTRELLA_K1 = '1') then
                if ESTRELLA(pixel_y - ESTRELLAK1_Y, pixel_x - ESTRELLAK1_X) /= X"3A0" then 
						color_v := ESTRELLA(pixel_y - ESTRELLAK1_Y, pixel_x - ESTRELLAK1_X); 
					 end if;
				end if;
				
				if (DIBUJAR_ESTRELLA_K2 = '1') then
					   if ESTRELLA(pixel_y - ESTRELLAK2_Y, pixel_x - ESTRELLAK2_X) /= X"3A0" then 
							color_v := ESTRELLA(pixel_y - ESTRELLAK2_Y, pixel_x - ESTRELLAK2_X);
						end if;
				end if;
				
				if (DIBUJAR_ESTRELLA_K3 = '1') then
						 if ESTRELLA(pixel_y - ESTRELLAK3_Y, pixel_x - ESTRELLAK3_X) /= X"3A0" then 
							color_v := ESTRELLA(pixel_y - ESTRELLAK3_Y, pixel_x - ESTRELLAK3_X); 
						end if;
				end if;

            --Estrellas Villano
            if (DIBUJAR_ESTRELLA_V1 = '1') then
						estrella_map_y := (pixel_y - ESTRELLAV1_Y)/2;
						estrella_map_x := (pixel_x - ESTRELLAV1_X)/2;
					if ESTRELLA_V(estrella_map_y, estrella_map_x) /= X"3A0" then 
						color_v := ESTRELLA_V(estrella_map_y, estrella_map_x); 
					end if;
				end if;	
					
            if (DIBUJAR_ESTRELLA_V2 = '1') then
						estrella_map_y := (pixel_y - ESTRELLAV2_Y)/2;
						estrella_map_x := (pixel_x - ESTRELLAV2_X)/2;
					if ESTRELLA_V(estrella_map_y, estrella_map_x) /= X"3A0" then 
						color_v := ESTRELLA_V(estrella_map_y, estrella_map_x); 
					end if;
				end if;	
					
					
            if (DIBUJAR_ESTRELLA_V3 = '1') then
                estrella_map_y := (pixel_y - ESTRELLAV3_Y)/2;
					 estrella_map_x := (pixel_x - ESTRELLAV3_X)/2;
					if ESTRELLA_V(estrella_map_y, estrella_map_x) /= X"3A0" then 
						color_v := ESTRELLA_V(estrella_map_y, estrella_map_x); 
					end if;
				end if;	 
					 
            if (DIBUJAR_ESTRELLA_V4 = '1') then
					estrella_map_y := (pixel_y - ESTRELLAV4_Y)/2;
					estrella_map_x := (pixel_x - ESTRELLAV4_X)/2;
					if ESTRELLA_V(estrella_map_y, estrella_map_x) /= X"3A0" then 
						color_v := ESTRELLA_V(estrella_map_y, estrella_map_x); 
					end if;
            end if;

            --Villano
            if (DIBUJAR_VILLANO = '1') then
                if VILLANO(SPRITE_V)(pixel_y - VILLANO_Y, pixel_x - VILLANO_X) /= X"3A0" then
                    color_v := VILLANO(SPRITE_V)(pixel_y - VILLANO_Y, pixel_x - VILLANO_X);
                end if;
            end if;

            --Kirby 
            if (DIBUJAR_KIRBY = '1') then
                if KIRBY(SPRITE_K)((pixel_y - KIRBY_Y), (pixel_x - KIRBY_X)) /= X"3A0" then
                    color_v := KIRBY(SPRITE_K)((pixel_y - KIRBY_Y), (pixel_x - KIRBY_X));
                end if;
            end if;
                
            --Corazones Kirby (Se dibujan SOBRE Kirby si pasa por ahí)
            if (DIBUJAR_CORAZON1 = '1') then
                corazon_map_y := (pixel_y - POS_CORAS_Y) / 2;
                corazon_map_x := (pixel_x - POS_CORA1_X) / 2;
                if CORAZON(corazon_map_y, corazon_map_x) /= X"3A0" then
						color_v := CORAZON(corazon_map_y, corazon_map_x); 
					 end if;
				end if;
                
            if (DIBUJAR_CORAZON2 = '1') then
                corazon_map_y := (pixel_y - POS_CORAS_Y) / 2;
                corazon_map_x := (pixel_x - POS_CORA2_X) / 2;
                if CORAZON(corazon_map_y, corazon_map_x) /= X"3A0" then 
						color_v := CORAZON(corazon_map_y, corazon_map_x); 
					end if;
				end if;
                
            if (DIBUJAR_CORAZON3 = '1') then
                corazon_map_y := (pixel_y - POS_CORAS_Y) / 2;
                corazon_map_x := (pixel_x - POS_CORA3_X) / 2;
                if CORAZON(corazon_map_y, corazon_map_x) /= X"3A0" then 
						color_v := CORAZON(corazon_map_y, corazon_map_x); 
					end if;
            end if;
            
            --Corazones Villano (Se dibujan SOBRE todo)
            if (DIBUJAR_CORAZON_M1 = '1') then
                corazon_map_y := (pixel_y - POS_CORAS_Y) / 2;
                corazon_map_x := (pixel_x - POS_CORAM1_X) / 2;
                if CORAZONM(corazon_map_y, corazon_map_x) /= X"3A0" then 
						color_v := CORAZONM(corazon_map_y, corazon_map_x); 
					 end if;
				end if;
				
            if (DIBUJAR_CORAZON_M2 = '1') then
                corazon_map_y := (pixel_y - POS_CORAS_Y) / 2;
                corazon_map_x := (pixel_x - POS_CORAM2_X) / 2;
                if CORAZONM(corazon_map_y, corazon_map_x) /= X"3A0" then 
						color_v := CORAZONM(corazon_map_y, corazon_map_x); 
					 end if;
				end if;
                
            if (DIBUJAR_CORAZON_M3 = '1') then
                corazon_map_y := (pixel_y - POS_CORAS_Y) / 2;
                corazon_map_x := (pixel_x - POS_CORAM3_X) / 2;
                if CORAZONM(corazon_map_y, corazon_map_x) /= X"3A0" then 
						color_v := CORAZONM(corazon_map_y, corazon_map_x); 
					 end if;
				end if;
                
            if (DIBUJAR_CORAZON_M4 = '1') then
                corazon_map_y := (pixel_y - POS_CORAS_Y) / 2;
                corazon_map_x := (pixel_x - POS_CORAM4_X) / 2;
                if CORAZONM(corazon_map_y, corazon_map_x) /= X"3A0" then 
						color_v := CORAZONM(corazon_map_y, corazon_map_x); 
					 end if;
				end if;
                
            if (DIBUJAR_CORAZON_M5 = '1') then
                corazon_map_y := (pixel_y - POS_CORAS_Y) / 2;
                corazon_map_x := (pixel_x - POS_CORAM5_X) / 2;
                if CORAZONM(corazon_map_y, corazon_map_x) /= X"3A0" then 
						color_v := CORAZONM(corazon_map_y, corazon_map_x); 
					 end if;
				end if;
                
            if (DIBUJAR_CORAZON_M6 = '1') then
                corazon_map_y := (pixel_y - POS_CORAS_Y) / 2;
                corazon_map_x := (pixel_x - POS_CORAM6_X) / 2;
                if CORAZONM(corazon_map_y, corazon_map_x) /= X"3A0" then 
						color_v := CORAZONM(corazon_map_y, corazon_map_x); 
					 end if;
				end if;
                
            if (DIBUJAR_CORAZON_M7 = '1') then
                corazon_map_y := (pixel_y - POS_CORAS_Y) / 2;
                corazon_map_x := (pixel_x - POS_CORAM7_X) / 2;
                if CORAZONM(corazon_map_y, corazon_map_x) /= X"3A0" then 
						color_v := CORAZONM(corazon_map_y, corazon_map_x); 
					 end if;
            end if;    
					 
            if (DIBUJAR_CORAZON_M8 = '1') then
                corazon_map_y := (pixel_y - POS_CORAS_Y) / 2;
                corazon_map_x := (pixel_x - POS_CORAM8_X) / 2;
                if CORAZONM(corazon_map_y, corazon_map_x) /= X"3A0" then 
						color_v := CORAZONM(corazon_map_y, corazon_map_x); 
					 end if;
				end if;
                
            if (DIBUJAR_CORAZON_M9 = '1') then
                corazon_map_y := (pixel_y - POS_CORAS_Y) / 2;
                corazon_map_x := (pixel_x - POS_CORAM9_X) / 2;
                if CORAZONM(corazon_map_y, corazon_map_x) /= X"3A0" then 
						color_v := CORAZONM(corazon_map_y, corazon_map_x);
					 end if;
				end if;
                
            if (DIBUJAR_CORAZON_M10 = '1') then
                corazon_map_y := (pixel_y - POS_CORAS_Y) / 2;
                corazon_map_x := (pixel_x - POS_CORAM10_X) / 2;
                if CORAZONM(corazon_map_y, corazon_map_x) /= X"3A0" then 
						color_v := CORAZONM(corazon_map_y, corazon_map_x); end if;
					 end if;
				end if;
				
				if (DIBUJAR_FLIP = '1') then
					if FLIP(pixel_y - POS_FLIPY, pixel_x - POS_FLIPX) /= X"3A0" then 
						color_v := FLIP(pixel_y - POS_FLIPY, pixel_x - POS_FLIPX); 
					end if;
				end if;
				
				if (DIBUJAR_FLOP = '1') then
					if FLOP(pixel_y - POS_FLOPY, pixel_x - POS_FLOPX) /= X"3A0" then 
						color_v := FLOP(pixel_y - POS_FLOPY, pixel_x - POS_FLOPX); 
					end if;
				end if;

        -- ASIGNACIÓN FINAL 
        R <= color_v(11 downto 8);
        G <= color_v(7 downto 4);
        B <= color_v(3 downto 0);
                
    end process;
end architecture;